class MinStack
{
    public Stack<Integer> stack;
    int cap;
    int minVal;
    public MinStack(int size)
    {
        this.stack= new Stack<>();
        this.minVal=Integer.MAX_VALUE;
        this.cap=size;
    }
    public void push(int val)
    {
        if(stack.size()==cap)
        {
            System.out.println("overflow");
            return;
        }
        if (stack.isEmpty())
        {
            stack.push(val);
            minVal=val;
            System.out.println("Pushed "+ val);
        }
        else if (val>=minVal)
        {
            stack.push(val);
            System.out.println("Pushed "+ val);
        }
        else
        {
            int Encode=(2*val)-minVal;
            stack.push(Encode);
            minVal=val;
            System.out.println("Pushed "+ val);
        }

    }
    public int pop()
    {
        if (stack.isEmpty())
        {
            return -1;
        }

        int top=stack.pop();

        if (top>=minVal)
        {
            return top;
        }
        else
        {
            int originalMin=minVal;
            int prevMin= 2*minVal-top;
            minVal=prevMin;
            return originalMin;
        }

    }
    public int peek()
    {
        if (stack.isEmpty())
        {
            return -1;
        }

        int top=stack.peek();

        if(top>=minVal)
        {
            return top;
        }
        else
        {
            return minVal;
        }
    }
    public int getMin()
    {
        if (stack.isEmpty())
        {
            return -1;
        }
        else
        {
            return minVal;
        }

    }

}

