class MaxProduct 
{
    public int findMaxProduct(int[] arr) 
    {
        Set<Integer> unique = new HashSet<>();
        for (int num : arr) 
        {
            unique.add(num);
        }
        if (unique.size() < 3) 
        {
            return -1;
        }

        PriorityQueue<Integer> minHeap = new PriorityQueue<>();

        for (int num : unique) 
        {
            minHeap.offer(num);
            if (minHeap.size() > 3) 
            {
                minHeap.poll();
            }
        }
        int product = 1;
        while (!minHeap.isEmpty()) 
        {
            product *= minHeap.poll();
        }

        return product;
    }
}

