class BuildTree {
    Node root;

    BuildTree() {
        this.root = null;
    }
    void insert(int data) {
        if (root == null) {
            root = new Node(data);
        } else {
            insertRecursion(root, data);
        }
    }

    void insertRecursion(Node node, int data) {
        if (data < node.data) {
            if (node.left == null) {
                node.left = new Node(data);
            } else {
                insertRecursion(node.left, data);
            }
        } else {
            if (node.right == null) {
                node.right = new Node(data);
            } else {
                insertRecursion(node.right, data);
            }
        }
    }

    boolean isLeaf(Node node) {
        return node != null && node.left == null && node.right == null;
    }

    void leftBoundary(Node root, List<Integer> res) {
        Node curr = root.left;
        while (curr != null) {
            if (!isLeaf(curr)) {
                res.add(curr.data);
            }
            curr = (curr.left != null) ? curr.left : curr.right;
        }
    }

    void rightBoundary(Node root, List<Integer> res) {
        Node curr = root.right;
        List<Integer> temp = new ArrayList<>();

        while (curr != null) {
            if (!isLeaf(curr)) {
                temp.add(curr.data);
            }
            curr = (curr.right != null) ? curr.right : curr.left;
        }

        for (int i = temp.size() - 1; i >= 0; i--) {
            res.add(temp.get(i));
        }
    }

    void leafNodes(Node root, List<Integer> res) {
        if (root == null) return;

        if (isLeaf(root)) {
            res.add(root.data);
            return;
        }

        leafNodes(root.left, res);
        leafNodes(root.right, res);
    }

    List<Integer> boundaryTraversal(Node root) {
        List<Integer> res = new ArrayList<>();
        if (root == null) return res;

        res.add(root.data);              
        leftBoundary(root, res);         
        leafNodes(root.left, res);       
        leafNodes(root.right, res);      
        rightBoundary(root, res);        

        return res;
    }
}

